package cn.mtplayer.tv;
import android.content.Context;import android.content.SharedPreferences;import android.os.Bundle;import android.os.Handler;import android.os.Looper;import android.view.Gravity;import android.view.KeyEvent;import android.view.View;import android.view.ViewGroup;import android.widget.Button;import android.widget.FrameLayout;import android.widget.LinearLayout;import android.widget.TextView;import android.widget.Toast;import androidx.appcompat.app.AppCompatActivity;import androidx.media3.common.MediaItem;import androidx.media3.common.util.UnstableApi;import androidx.media3.exoplayer.ExoPlayer;import androidx.media3.ui.PlayerView;
@UnstableApi public final class TvPlayerActivity extends AppCompatActivity{private ExoPlayer player;private PlayerView view;private LinearLayout controls;private final Handler timer=new Handler(Looper.getMainLooper());private SharedPreferences prefs;private String key;private boolean introDone=false,outroDone=false;private final Runnable hide=()->{controls.setVisibility(View.GONE);view.hideController();};private final Runnable tick=new Runnable(){public void run(){if(player!=null&&player.isPlaying()){long pos=player.getCurrentPosition(),duration=player.getDuration();int intro=prefs.getInt(key+".intro",0),outro=prefs.getInt(key+".outro",0);if(!introDone&&intro>0&&pos<intro*1000L){introDone=true;player.seekTo(intro*1000L);}if(!outroDone&&outro>0&&duration>0&&duration-pos<=outro*1000L){outroDone=true;player.pause();toast("已到达片尾跳过点");}prefs.edit().putLong(key+".position",pos).apply();}timer.postDelayed(this,1000);}};
@Override protected void onCreate(Bundle b){super.onCreate(b);getWindow().getDecorView().setSystemUiVisibility(View.SYSTEM_UI_FLAG_FULLSCREEN|View.SYSTEM_UI_FLAG_HIDE_NAVIGATION|View.SYSTEM_UI_FLAG_IMMERSIVE_STICKY);prefs=getSharedPreferences("mtplayer.playback",Context.MODE_PRIVATE);String url=getIntent().getStringExtra("url"),title=getIntent().getStringExtra("title");key=getIntent().getStringExtra("mediaKey");if(key==null)key="stream:"+url.hashCode();setContentView(screen(title));player=new ExoPlayer.Builder(this).build();view.setPlayer(player);player.setMediaItem(MediaItem.fromUri(url));player.prepare();long resume=prefs.getLong(key+".position",0);if(resume>0)player.seekTo(resume);player.play();showControls();timer.post(tick);}
private View screen(String title){FrameLayout root=new FrameLayout(this);root.setBackgroundColor(android.graphics.Color.BLACK);view=new PlayerView(this);view.setUseController(true);view.setControllerShowTimeoutMs(5000);root.addView(view,new FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.MATCH_PARENT));controls=new LinearLayout(this);controls.setOrientation(LinearLayout.VERTICAL);controls.setPadding(TvUi.dp(this,28),TvUi.dp(this,18),TvUi.dp(this,28),TvUi.dp(this,18));controls.setBackgroundColor(0xD1090C10);controls.addView(TvUi.title(this,title==null?"MT播放器 TV":title,24),TvUi.matchWrap());LinearLayout row=new LinearLayout(this);row.setGravity(Gravity.CENTER);String[] labels={"上集","－10 秒","播放/暂停","＋10 秒","下集","设片头","设片尾","清除跳过","静音","1.0×"};for(String label:labels){Button x=TvUi.button(this,label,"播放/暂停".equals(label));row.addView(x,new LinearLayout.LayoutParams(0,TvUi.dp(this,62),1));switch(label){case"－10 秒":x.setOnClickListener(v->player.seekTo(Math.max(0,player.getCurrentPosition()-10000)));break;case"播放/暂停":x.setOnClickListener(v->{if(player.isPlaying())player.pause();else player.play();});break;case"＋10 秒":x.setOnClickListener(v->player.seekTo(player.getCurrentPosition()+10000));break;case"设片头":x.setOnClickListener(v->{prefs.edit().putInt(key+".intro",(int)(player.getCurrentPosition()/1000)).apply();toast("已保存本影片片头");});break;case"设片尾":x.setOnClickListener(v->{prefs.edit().putInt(key+".outro",(int)Math.max(0,(player.getDuration()-player.getCurrentPosition())/1000)).apply();toast("已保存本影片片尾");});break;case"清除跳过":x.setOnClickListener(v->{prefs.edit().remove(key+".intro").remove(key+".outro").apply();toast("已清除本影片跳过设置");});break;case"静音":x.setOnClickListener(v->{player.setVolume(player.getVolume()>0?0:1);x.setText(player.getVolume()>0?"静音":"取消静音");});break;case"1.0×":x.setOnClickListener(v->{float n=player.getPlaybackParameters().speed<1.25f?1.25f:player.getPlaybackParameters().speed<1.5f?1.5f:player.getPlaybackParameters().speed<2?2:1;player.setPlaybackSpeed(n);x.setText(n+"×");});break;default:x.setEnabled(false);}}HorizontalScrollViewFix wrap=new HorizontalScrollViewFix(this);wrap.addView(row);controls.addView(wrap,TvUi.matchWrap());root.addView(controls,new FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT,Gravity.BOTTOM));return root;}
private void showControls(){controls.setVisibility(View.VISIBLE);view.showController();timer.removeCallbacks(hide);timer.postDelayed(hide,5000);if(controls.getChildCount()>1)((ViewGroup)((ViewGroup)controls.getChildAt(1)).getChildAt(0)).getChildAt(2).requestFocus();}@Override public boolean dispatchKeyEvent(KeyEvent e){if(e.getAction()==KeyEvent.ACTION_DOWN){showControls();if(e.getKeyCode()==KeyEvent.KEYCODE_DPAD_CENTER&&controls.getVisibility()!=View.VISIBLE)return true;}return super.dispatchKeyEvent(e);}@Override protected void onPause(){if(player!=null){prefs.edit().putLong(key+".position",player.getCurrentPosition()).apply();player.pause();}super.onPause();}@Override protected void onDestroy(){timer.removeCallbacksAndMessages(null);if(player!=null)player.release();super.onDestroy();}private void toast(String s){Toast.makeText(this,s,Toast.LENGTH_SHORT).show();}private static final class HorizontalScrollViewFix extends android.widget.HorizontalScrollView{HorizontalScrollViewFix(Context c){super(c);setHorizontalScrollBarEnabled(false);setFillViewport(true);}}}
